                  <div className="grade">{c.grade ?? '-'}</div>
                </div>
              </div>

              <div className="course-body">
                <div>Credits: <strong>{c.creditsEarned ?? 0}</strong></div>
                
              </div>
            </div>
          )) }
        </div>
      </section>

